// Lights-out scene audio (Obsidian 881/881b, normalized 911) - the three
// clips the user supplied, trimmed per spec (gb minus its last 3s; br the
// 20-32s span; bsc the 7s loop), LOUDNESS-NORMALIZED (ffmpeg loudnorm ~-18
// LUFS + a gentle compressor so all three sit at a consistent level) and
// compressed to mono mp3, base64-embedded as data URIs. Dynamically imported
// only when the 18+ fade scene fires; played through the SFX volume chain.
export const bscLoop = 'data:audio/mpeg;base64,';
export const gbOnce = 'data:audio/mpeg;base64,';
export const brOnce = 'data:audio/mpeg;base64,';
